// ETAPA 2 - Logica de dominio
// Responsabilidad unica: clasificar y generar respuesta de negocio
// Sin conocimiento de integraciones externas ni detalles de persistencia

const { run_id, start_ts, payload } = $input.item.json;
const mensaje = payload.message.toLowerCase();

const e2_start = new Date().toISOString();

let respuesta = '';
let categoria = 'general';
let prioridad = 'baja';
let requiereEscalacion = false;

// Reglas de negocio centralizadas y testables
const REGLAS = [
  {
    id: 'R001',
    condicion: (m) => m.includes('urgente') || m.includes('critico') || m.includes('emergencia'),
    categoria: 'incidente',
    prioridad: 'alta',
    respuesta: 'Tu solicitud fue marcada como URGENTE. Un agente te contactara en menos de 30 minutos.',
    escalacion: true
  },
  {
    id: 'R002',
    condicion: (m) => m.includes('factura') || m.includes('pago') || m.includes('cobro'),
    categoria: 'facturacion',
    prioridad: 'media',
    respuesta: 'Tu consulta de facturacion fue recibida. El departamento de pagos te respondera en 24 horas habiles.',
    escalacion: false
  },
  {
    id: 'R003',
    condicion: (m) => m.includes('error') || m.includes('falla') || m.includes('no funciona'),
    categoria: 'soporte_tecnico',
    prioridad: 'media',
    respuesta: 'Hemos registrado tu reporte tecnico. Por favor comparte el codigo de error si tienes uno.',
    escalacion: false
  },
  {
    id: 'R004',
    condicion: (m) => m.includes('hola') || m.includes('buenos') || m.includes('buenas'),
    categoria: 'saludo',
    prioridad: 'baja',
    respuesta: 'Hola! Soy el asistente de soporte. En que puedo ayudarte hoy?',
    escalacion: false
  }
];

const reglaAplicada = REGLAS.find(r => r.condicion(mensaje));

if (reglaAplicada) {
  categoria = reglaAplicada.categoria;
  prioridad = reglaAplicada.prioridad;
  respuesta = reglaAplicada.respuesta;
  requiereEscalacion = reglaAplicada.escalacion;
} else {
  respuesta = 'Gracias por tu mensaje. Un agente revisara tu solicitud pronto.';
}

const e2_end = new Date().toISOString();
const duracion_ms = new Date(e2_end) - new Date(e2_start);

// Log estructurado estandar
console.log(JSON.stringify({
  run_id,
  etapa: 'E2_dominio',
  status: 'ok',
  categoria,
  prioridad,
  requiereEscalacion,
  regla_aplicada: reglaAplicada ? reglaAplicada.id : 'DEFAULT',
  e2_start,
  e2_end,
  duracion_ms
}));

return [{
  json: {
    run_id,
    start_ts,
    e2_start,
    e2_end,
    categoria,
    prioridad,
    respuesta,
    requiereEscalacion,
    payload
  }
}];
